179	      return Number.parseFloat(number).toString().replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1,');
180	    }
181	    function formatDate(input) {
182	      if (input == null) return '';
183	      if (input.includes('-')) {
184	        const datePart = input.match(/\d+/g);
185	        const year = datePart[0].substring();
186	        const month = datePart[1];
187	        const day = datePart[2];
188	        return month + '/' + day + '/' + year;
189	      }
190	      return input;
