198	    // Parses the parts manually to avoid timezone shifts from new Date(string).
199	    function formatQuotedDate(input) {
200	      if (input == null || input === '') return '';
201	      const months = ['January','February','March','April','May','June',
202	        'July','August','September','October','November','December'];
203	      const parts = String(input).match(/\d+/g);
204	      if (!parts || parts.length < 3) return String(input);
205	      let year, month, day;
206	      if (String(input).includes('-')) {
207	        // YYYY-MM-DD
208	        [year, month, day] = parts;
209	      } else {
210	        // MM/DD/YYYY
211	        [month, day, year] = parts;
212	      }
213	      const monthName = months[Number(month) - 1] || month;
214	      return `${monthName} ${Number(day)} ${year}`;
215	    }
