17	export class UploadFileComponent {
18	  public files: any[] = [];
19	  isLoading = false;
20	
21	  constructor(private _snackBar: MatSnackBar,
22	    private commonModule: CommonModule,
23	    public dialog: MatDialog,
24	    private dialogRef: MatDialogRef<UploadFileComponent>,
25	    private itemService: itemService,
26	    private helperService:HelperService,
27	    private http: HttpClient,
28	    private itemDetailService: ItemDetailService,
29	    @Inject(MAT_DIALOG_DATA) public data: { itemId: number, value: string }) {}
30	
31	  onFileChange(pFileList: File[]) {
32	    this.files = Object.keys(pFileList).map(key => pFileList[key]);
33	  }
34	
35	  onSave() {
36	    if (this.isLoading) { return }
37	    if (!this.files.length) {
38	      this._snackBar.open("You need to choose file first!", 'Close', {
39	        duration: 2000,
40	      });
41	      return;
42	    }
43	    const file = this.files[0];
44	    let contentType = file.type;
45	    const extension = file.name.split('.').pop().toLowerCase();
46	    let fileName;
47	    if (extension === 'ai') {
48	      fileName = `${new Date().getTime()}-${file.name.toLowerCase().replace('.ai', '.pdf')}`;
49	      contentType = 'application/pdf';
50	    } else if (['ai', 'pdf'].includes(extension)) {
51	      fileName = `${new Date().getTime()}-${file.name.toLowerCase()}`;
52	    } else {
53	      fileName = 'images-' + `${new Date().getTime()}-${file.name.toLowerCase()}`;
54	    }
55	    this.isLoading = true;
56	    this.itemService
57	      .getPreSignedUrl({ fileName, contentType })
58	      .subscribe((res: { signedUrl: string }) => {
59	        const signedUrl = res.signedUrl
60	        const headers = new Headers({ 'Content-Type': contentType, 'x-amz-acl': 'public-read' });
61	        const putConfig = { method: 'PUT', body: file, headers: headers }
62	        fetch(signedUrl, putConfig)
63	          .then(async output => {
64	            if(!this.data.itemId){
65	              const sharedLink = this.helperService.buildPublicUrl(fileName);
66	              const thumbName = `thumbs-${fileName.replace('images-', '')}`;
67	              const thumbFile = await this.helperService.resizeImage(file, thumbName);
68	              await this.helperService.saveToDigitalOceanAndDB(thumbName, contentType, thumbFile);
69	              const thumbSharedLink = this.helperService.buildPublicUrl(thumbName);
70	              this.isLoading = false;
71	              return this.dialogRef.close({sharedLink, thumbSharedLink});
72	            }
73	              const body = this.data.value === 'rfq'
74	              ? { flag: 'rfq-update', fileName }
75	              : {
76	                  flag: 'item-attachment-create',
77	                  item_num_id_fk: this.data.itemId,
78	                  attachment_type: contentType,
79	                  attachment_display_name: contentType.split("/")[0],
80	                  fileName
81	                };
82	
83	              this.itemService
84	                .saveTechLink(body, this.data.itemId)
85	                .pipe(take(1))
86	                .subscribe((res: { sharedLink: string }) => {
87	                  this.isLoading = false;
88	                  this.dialogRef.close(res.sharedLink);
89	              });
90	      })
91	  })
92	}
93	
94	  onCancel() {
95	    this.dialogRef.close()
96	  }
97	
98	  removeFile(pIndex): void {
99	    this.deleteFromArray(pIndex);
100	  }
101	
102	  deleteFromArray(index) {
103	    this.files.splice(index, 1);
104	  }
105	}
